home.script:
fn AppButton(label, color, onTap) {
  return InkWell({ onTap: onTap, borderRadius: 8 }, [Box({ padding: 16, borderRadius: 8, color: color }, [Text(label, { fontSize: 16, fontWeight: "bold", color: "white" })])])
}
let counter = Obs(0)
fn build() {
  return Box({ color: "#f5f5f5", height: "infinity", width: "infinity" }, [Column({ spacing: 24, mainAxisAlignment: "center", crossAxisAlignment: "center" }, [Text("Welcome to KromLang! 🚀", { fontSize: 24, fontWeight: "bold", color: "#333" }), Obx({ builder: "counterBuilder" }), Row({ spacing: 12 }, [AppButton("Increment", "#4CAF50", "onIncrement"), AppButton("Decrement", "#f44336", "onDecrement")])])])
}
fn counterBuilder() {
  return Text("Count: " + counter.value, { fontSize: 48, fontWeight: "bold", color: "#333" })
}
fn onIncrement() {
  counter.set(counter.value + 1)
}
fn onDecrement() {
  counter.set(counter.value - 1)
}
